"""Steel/mixed section model."""

import copy
import math
from typing import Optional, Union

from structuralcodes.core._section_results import UltimateBendingMomentResults
from structuralcodes.geometry import CompoundGeometry, SurfaceGeometry, SurfaceGeometry
from structuralcodes.sections import GenericSection

from fhecor_structuralcodes.core._section_results import ULSBucklingSummaryEntry
from fhecor_structuralcodes.geometry import Panel, Plate

ExtraGeometry = Union[SurfaceGeometry, SurfaceGeometry, CompoundGeometry]
Point2D = tuple[float, float]  # (y, z)
StrainPlane = tuple[float, float, float]  # (eps_a, chi_y, chi_z)


class SteelSection:
    """Mixed section model with multiple panels and optional extra geometries."""

    def __init__(
        self,
        panels: Optional[list[Panel]] = None,
        extra_geometries: Optional[list[ExtraGeometry]] = None,
        panel_adjacency_tolerance: float = 50,
    ):
        self.panels = panels or []
        self.extra_geometries = extra_geometries or []
        self.panel_adjacency_tolerance = panel_adjacency_tolerance
        self._section: Optional[GenericSection] = None

    @staticmethod
    def _strain_at_point(y: float, z: float, strain: StrainPlane) -> float:
        """Evaluate linear strain plane at point (y, z)."""
        eps_a, chi_y, chi_z = strain
        return eps_a + chi_y * z - chi_z * y

    @classmethod
    def _plate_edge_stresses(cls, plate: Plate, strain: StrainPlane) -> tuple[float, float, float]:
        """Compute constitutive-law stresses at plate start and end edges.
        alfaC is the ratio of the plate in compression between 0 and 1, and takes
        into account the plastification if exists.

        Returns:
            sigma_end1: stress at the initial edge in MPa (float). Tension (+), C (-).
            sigma_end2: stress at the end edge in MPa (float).  Tension (+), C (-).
            alfaC: Is the ratio of the plate in compression
        """
        y1, z1 = plate.y0, plate.z0
        y2, z2 = plate.endpoint

        eps1 = cls._strain_at_point(y1, z1, strain)
        eps2 = cls._strain_at_point(y2, z2, strain)
        law = plate.material.material_analysis.constitutive_law
        sigma_end1 = float(law.get_stress(eps1))
        sigma_end2 = float(law.get_stress(eps2))

        if eps1 * eps2 < 0 and eps1 < 0:
            alfaC = (abs(eps1) * plate.b / (abs(eps2) + abs(eps1))) / plate.b
        elif eps1 * eps2 < 0 and eps1 > 0:
            alfaC = (abs(eps2) * plate.b / (abs(eps2) + abs(eps1))) / plate.b
        elif eps1 > 0 and eps2 > 0:
            alfaC = 0
        else:
            alfaC = 1
        return sigma_end1, sigma_end2, alfaC

    @staticmethod
    def _point_segment_distance(point: Point2D, seg_start: Point2D, seg_end: Point2D) -> float:
        """Return shortest distance from a point to a finite segment."""
        py, pz = point
        y1, z1 = seg_start
        y2, z2 = seg_end
        vy = y2 - y1
        vz = z2 - z1
        wy = py - y1
        wz = pz - z1
        seg_len2 = vy * vy + vz * vz
        if seg_len2 == 0.0:
            return math.hypot(py - y1, pz - z1)
        t = max(0.0, min(1.0, (wy * vy + wz * vz) / seg_len2))
        proj_y = y1 + t * vy
        proj_z = z1 + t * vz
        return math.hypot(py - proj_y, pz - proj_z)

    def _is_edge_supported_by_adjacent_panels(self, panel_index: int, edge_point: Point2D, tolerance: float) -> bool:
        """Check whether a panel edge lies on any adjacent panel within tolerance."""
        for idx, other_panel in enumerate(self.panels):
            if idx == panel_index:
                continue
            other_start, other_end = other_panel.endpoints
            if self._point_segment_distance(edge_point, other_start, other_end) <= tolerance:
                return True
        return False

    @staticmethod
    def _cross_2d(a: Point2D, b: Point2D) -> float:
        """Return 2D scalar cross product."""
        return a[0] * b[1] - a[1] * b[0]

    def _projection_on_panel_if_close(
        self, panel: Panel, seg_start: Point2D, seg_end: Point2D, point: Point2D, tolerance: float
    ) -> Optional[float]:
        """Return clamped panel abscissa if point is close to the panel segment."""
        if self._point_segment_distance(point, seg_start, seg_end) > tolerance:
            return None
        s_coord = panel.abscissa_at(point)
        if -tolerance <= s_coord <= panel.b + tolerance:
            return max(0.0, min(panel.b, s_coord))
        return None

    def _intersection_abscissas_with_panel(self, panel: Panel, other_panel: Panel, tolerance: float) -> list[float]:
        """Return panel abscissas where another panel intersects or touches it."""
        p1, p2 = panel.endpoints
        q1, q2 = other_panel.endpoints
        r = (p2[0] - p1[0], p2[1] - p1[1])
        s = (q2[0] - q1[0], q2[1] - q1[1])
        rxs = self._cross_2d(r, s)
        qmp = (q1[0] - p1[0], q1[1] - p1[1])
        result: list[float] = []

        if abs(rxs) > 1e-12:
            t = self._cross_2d(qmp, s) / rxs
            u = self._cross_2d(qmp, r) / rxs
            if -tolerance <= t <= 1.0 + tolerance and -tolerance <= u <= 1.0 + tolerance:
                t_clamped = max(0.0, min(1.0, t))
                result.append(t_clamped * panel.b)

        for point in (q1, q2):
            projected = self._projection_on_panel_if_close(
                panel=panel, seg_start=p1, seg_end=p2, point=point, tolerance=tolerance
            )
            if projected is not None:
                result.append(projected)

        return result

    @staticmethod
    def _panel_plate_boundaries(base_plates: list[Plate]) -> list[float]:
        """Build cumulative abscissa boundaries from contiguous base plates."""
        boundaries: list[float] = [0.0]
        running = 0.0
        for plate in base_plates:
            running += plate.b
            boundaries.append(running)
        return boundaries

    @staticmethod
    def _clean_boundaries(boundaries: list[float], panel_length: float, tolerance: float) -> list[float]:
        """Round, clip and normalize split boundaries to [0, panel_length]."""
        rounded = sorted(set(round(v, 6) for v in boundaries))
        clipped = [v for v in rounded if -tolerance <= v <= panel_length + tolerance]
        return [0.0] + [v for v in clipped if tolerance < v < panel_length - tolerance] + [panel_length]

    @staticmethod
    def _plate_position_by_index(i: int, total_segments: int) -> str:
        """Return default plate position label based on segment index."""
        if total_segments == 1:
            return 'internal'
        if i == 0:
            return 'end_supported_edge'
        if i == total_segments - 1:
            return 'start_supported_edge'
        return 'internal'

    def _build_base_plates_with_panel_intersections(self, panel_index: int, tolerance: float) -> list[Plate]:
        """Split one panel base plates using intersections with other panels."""
        panel = self.panels[panel_index]
        base_plates = panel.base_plates
        if not base_plates:
            return []

        alpha = math.radians(panel.alfa)
        cos_a = math.cos(alpha)
        sin_a = math.sin(alpha)

        boundaries = self._panel_plate_boundaries(base_plates)

        for idx, other_panel in enumerate(self.panels):
            if idx == panel_index:
                continue
            boundaries.extend(self._intersection_abscissas_with_panel(panel, other_panel, tolerance))

        clean_boundaries = self._clean_boundaries(boundaries, panel.b, tolerance)

        rebuilt: list[Plate] = []
        total_segments = len(clean_boundaries) - 1
        for i in range(total_segments):
            s_start = clean_boundaries[i]
            width = clean_boundaries[i + 1] - s_start
            if width <= tolerance:
                continue
            rebuilt.append(
                Plate(
                    material=panel.material,
                    b=width,
                    t=panel.t,
                    y0=panel.y0 + s_start * cos_a,
                    z0=panel.z0 + s_start * sin_a,
                    alfa=panel.alfa,
                    plate_position=self._plate_position_by_index(i, total_segments),
                )
            )

        return rebuilt

    @staticmethod
    def _apply_extreme_plate_support(base_plates: list[Plate], start_supported: bool, end_supported: bool) -> None:
        """Adjust extreme plate positions according to support at panel ends."""
        if len(base_plates) == 1:
            if start_supported and end_supported:
                base_plates[0].plate_position = 'internal'
            elif start_supported:
                base_plates[0].plate_position = 'start_supported_edge'
            elif end_supported:
                base_plates[0].plate_position = 'end_supported_edge'
            return

        base_plates[0].plate_position = 'internal' if start_supported else 'end_supported_edge'
        base_plates[-1].plate_position = 'internal' if end_supported else 'start_supported_edge'

    def update_panel_extreme_plate_positions(self, tolerance: Optional[float] = None) -> None:
        """Set edge support state and build analysis plates for each panel."""
        if tolerance is None:
            tolerance = self.panel_adjacency_tolerance

        for idx, panel in enumerate(self.panels):
            base_plates = self._build_base_plates_with_panel_intersections(panel_index=idx, tolerance=tolerance)
            if not base_plates:
                panel.set_analysis_plates_from_base([])
                continue

            panel_start, panel_end = panel.endpoints
            start_supported = self._is_edge_supported_by_adjacent_panels(idx, panel_start, tolerance)
            end_supported = self._is_edge_supported_by_adjacent_panels(idx, panel_end, tolerance)

            self._apply_extreme_plate_support(base_plates, start_supported, end_supported)
            panel.set_analysis_plates_from_base(base_plates)

    def build_compound_and_panel_plate_map(self) -> tuple[CompoundGeometry, dict[int, list[Plate]]]:
        """Build compound geometry for section analysis and panel-to-plate mapping."""
        geometries: list[ExtraGeometry] = []
        panel_plate_map: dict[int, list[Plate]] = {}

        self.update_panel_extreme_plate_positions()

        for idx, panel in enumerate(self.panels):
            plates = panel.analysis_plates
            panel_plate_map[idx] = plates
            geometries.extend(p.to_line_geometry() for p in plates)

        geometries.extend(self.extra_geometries)

        if not geometries:
            raise ValueError('SectionModel has no geometries to analyze.')

        return CompoundGeometry(geometries), panel_plate_map

    @staticmethod
    def _clone_plate(plate: Plate, geometry_only: bool = False) -> Plate:
        """Create a copy of a Plate, optionally geometry-only (no stress/buckling)."""
        plate_clone = copy.copy(plate)
        if geometry_only:
            plate_clone.stress_state = None
            plate_clone.buckling_results = None
        else:
            plate_clone.stress_state = copy.copy(plate.stress_state) if plate.stress_state else None
            plate_clone.buckling_results = copy.copy(plate.buckling_results) if plate.buckling_results else None
        return plate_clone

    @staticmethod
    def _build_uls_buckling_summary_by_origin(
        effective_map: dict[int, list[Plate]], origin_plates_map: dict[int, list[Plate]]
    ) -> dict[int, ULSBucklingSummaryEntry]:
        """Aggregate ULS buckling summary per original plate id."""
        child_count: dict[int, int] = {}
        for plates in effective_map.values():
            for plate in plates:
                origin_id = plate.origin_plate_id
                child_count[origin_id] = child_count.get(origin_id, 0) + 1

        summary: dict[int, ULSBucklingSummaryEntry] = {}
        for plates in origin_plates_map.values():
            for plate in plates:
                origin_id = plate.plate_id
                ss = plate.stress_state
                br = plate.buckling_results
                summary[origin_id] = ULSBucklingSummaryEntry(
                    origin_plate_id=origin_id,
                    class_plate=None if ss is None else ss.class_plate,
                    rho=None if br is None else br.rho,
                    beff=None if br is None else br.beff,
                    be1=None if br is None else br.be1,
                    be2=None if br is None else br.be2,
                    plate_position=plate.plate_position,
                    num_effective_children=child_count.get(origin_id, 0),
                    k_sigma=None if br is None else br.k_sigma,
                    lambda_p=None if br is None else br.lambda_p,
                    sigma_cr=None if br is None else br.sigma_cr,
                )
        return summary

    @staticmethod
    def _resolve_plate_material(plate: Plate):
        """Return the correct material for a plate based on its stress state class."""
        if plate.stress_state is not None and plate.stress_state.class_plate in (3, 4):
            return plate.material.material_sc_el
        return plate.material.material_sc_ep

    def _build_compound_from_panel_plate_map(
        self, panel_plate_map: dict[int, list[Plate]], *, class_based_material: bool = False
    ) -> CompoundGeometry:
        """Build compound geometry from a provided panel plate map."""
        geometries: list[ExtraGeometry] = []
        for plates in panel_plate_map.values():
            for p in plates:
                mat = self._resolve_plate_material(p) if class_based_material else None
                geometries.append(p.to_line_geometry(material=mat))
        geometries.extend(self.extra_geometries)
        if not geometries:
            raise ValueError('SectionModel has no geometries to analyze.')
        return CompoundGeometry(geometries)

    def _build_next_effective_panel_plate_map(
        self, panel_plate_map: dict[int, list[Plate]]
    ) -> tuple[dict[int, list[Plate]], float]:
        """Build next effective-geometry map and return max relative beff change."""
        next_map: dict[int, list[Plate]] = {}
        max_delta_beff = 0.0

        for idx, plates in panel_plate_map.items():
            next_plates: list[Plate] = []
            for plate in plates:
                is_class4 = (
                    plate.stress_state is not None
                    and plate.stress_state.class_plate == 4
                    and plate.buckling_results is not None
                    and (not plate.non_buckling)
                )
                if not is_class4:
                    next_plates.append(self._clone_plate(plate))
                    continue

                old_beff = plate.b
                effective_plates = plate.build_effective_plates_class4()
                for eff_p in effective_plates:
                    eff_p.stress_state = copy.copy(plate.stress_state)
                    eff_p.buckling_results = copy.copy(plate.buckling_results)
                new_beff = sum(p.b for p in effective_plates)
                denom = max(abs(old_beff), 1e-12)
                delta = abs(new_beff - old_beff) / denom
                max_delta_beff = max(max_delta_beff, delta)
                next_plates.extend(effective_plates)

            next_map[idx] = next_plates

        return next_map, max_delta_beff

    def solveULS(
        self, n: float, theta: float, tol_beff: float = 1e-5, max_iter_eff: int = 10
    ) -> tuple[dict[int, list[Plate]], UltimateBendingMomentResults, dict[int, ULSBucklingSummaryEntry]]:
        """Solve ULS with effective class-4 geometry and return buckling summary.

        Algorithm:
            1. Build gross compound geometry and determine plate positions.
            2. Compute ULS strain plane on the gross section (ElasticPlastic for all).
            3. Evaluate plate stress states and class on the gross geometry.
            4. Iteratively build effective geometry, re-solve and re-evaluate
               **on the original plates** until the relative beff change is
               below *tol_beff*.  The class and beff are always computed
               from the original plate geometry (b, t); the effective
               sub-plates are only used for the section analysis that
               yields a new strain plane.
            5. Final solve on the converged effective geometry with
               class-based materials (elastic for class 3/4, EP for 1/2).

        Args:
            n: Axial force [N].
            theta: Angle of the neutral axis [rad].
                (theta=0 -> compression on bottom, theta=pi -> compression
                on top)
            tol_beff: Convergence tolerance on max relative beff change.
            max_iter_eff: Max effective-geometry iterations.

        Returns:
            A tuple with:
                - effective_map: final effective plate geometry map.
                - ultimate bending strength results.
                - buckling summary aggregated by original plate id.
        """
        # 1. Build gross compound and panel plate map.
        compoundG, panel_plate_map = self.build_compound_and_panel_plate_map()
        section = GenericSection(compoundG, integrator='marin')
        # TODO move section to centroid to avoid additional moments for eccentricities
        # (if no reference point is provided).

        # 2. Compute ULS strain plane on the gross section.
        res_uls = section.section_calculator.calculate_bending_strength(theta, n)
        strain_uls = (res_uls.eps_a, res_uls.chi_y, res_uls.chi_z)

        # 3. Evaluate plate stress states and class on the gross geometry
        #    using the elastic-plastic constitutive law.
        for plates in panel_plate_map.values():
            for plate in plates:
                plate.material.set_analysis_constitutive_law(1)
                sigma_end1, sigma_end2, alfaC = self._plate_edge_stresses(plate=plate, strain=strain_uls)
                plate.update_plate_stress_state(sigma_end1, sigma_end2, alfaC)
                if plate.stress_state.class_plate == 4:
                    plate.calculate_buckling_reductions(plate.stress_state)

        # 4. Iterate: build effective → solve → re-evaluate on ORIGINAL
        #    plates.  The class and beff are always computed from the
        #    original plate geometry (b, t); the effective sub-plates are
        #    only used for the section analysis that yields a new strain
        #    plane.
        converged = not any(
            p.stress_state is not None and p.stress_state.class_plate == 4
            for plates in panel_plate_map.values()
            for p in plates
        )

        for _ in range(max_iter_eff):
            if converged:
                break

            prev_beff: dict[int, float] = {}
            for plates in panel_plate_map.values():
                for plate in plates:
                    br = plate.buckling_results
                    if br is not None and br.beff is not None:
                        prev_beff[plate.plate_id] = br.beff

            effective_map, _ = self._build_next_effective_panel_plate_map(panel_plate_map)
            compound_eff = self._build_compound_from_panel_plate_map(effective_map, class_based_material=True)
            section_eff = GenericSection(compound_eff, integrator='marin')
            res_eff = section_eff.section_calculator.calculate_bending_strength(theta, n)
            strain_eff = (res_eff.eps_a, res_eff.chi_y, res_eff.chi_z)

            for plates in panel_plate_map.values():
                for plate in plates:
                    plate.material.set_analysis_constitutive_law(1)
                    sigma_end1, sigma_end2, alfaC = self._plate_edge_stresses(plate=plate, strain=strain_eff)
                    plate.update_plate_stress_state(sigma_end1, sigma_end2, alfaC)
                    if plate.stress_state.class_plate == 4 and not plate.non_buckling:
                        plate.calculate_buckling_reductions(plate.stress_state)

            max_delta = 0.0
            for plates in panel_plate_map.values():
                for plate in plates:
                    br = plate.buckling_results
                    if br is None or br.beff is None:
                        continue
                    pid = plate.plate_id
                    if pid in prev_beff:
                        old = prev_beff[pid]
                        delta = abs(br.beff - old) / max(abs(old), 1e-12)
                        max_delta = max(max_delta, delta)

            converged = max_delta < tol_beff

        if not converged:
            raise ValueError('solveULS: max effective-geometry iterations reached. ' 'Try increasing max_iter_eff.')

        # 5. Final solve on the converged effective geometry.
        final_effective_map, _ = self._build_next_effective_panel_plate_map(panel_plate_map)
        compound_final = self._build_compound_from_panel_plate_map(final_effective_map, class_based_material=True)
        section_final = GenericSection(compound_final, integrator='marin')
        res_uls_final = section_final.section_calculator.calculate_bending_strength(theta, n)

        buckling_summary = self._build_uls_buckling_summary_by_origin(
            effective_map=final_effective_map, origin_plates_map=panel_plate_map
        )
        return final_effective_map, res_uls_final, buckling_summary
